<template><div class="page-container"><el-card><template #header><span>成本计价</span><el-button size="small" type="primary" style="float:right" @click="handleRecalc">手动重算</el-button></template><el-form :inline="true"><el-form-item label="计价月份"><el-input v-model="f.valuation_month" placeholder="YYYY-MM" clearable style="width:120px"/></el-form-item><el-form-item label="搜索"><el-input v-model="f.search" placeholder="SKU/MSKU" clearable style="width:200px"/></el-form-item><el-form-item><el-button type="primary" @click="search">查询</el-button></el-form-item></el-form><el-table :data="list" border stripe v-loading="loading"><el-table-column prop="sku" label="SKU" width="120"/><el-table-column prop="msku" label="MSKU" width="120"/><el-table-column prop="source_doc_no" label="源头单据号" width="130"/><el-table-column prop="cost_source" label="成本来源" width="100"/><el-table-column prop="purchase_cost" label="采购成本" width="100"/><el-table-column prop="shipping_cost" label="头程费用" width="100"/><el-table-column prop="valuation_month" label="计价月份" width="100"/></el-table><el-pagination v-model:current-page="p.page" layout="total,prev,pager,next" :total="p.total" @current-change="load"/></el-card></div></template>
<script setup>import { ref, reactive, onMounted } from 'vue'; import { getCostValuations } from '@/api/finance'
const f = reactive({ valuation_month: '', search: '' }); const list = ref([]); const loading = ref(false); const p = reactive({ page: 1, total: 0 })
async function load() { loading.value = true; try { const data = await getCostValuations({ ...f, page: p.page }); list.value = data?.results || data || []; p.total = data?.count || 0 } catch { } finally { loading.value = false } }
function search() { p.page = 1; load() }
function handleRecalc() { /* recalc */ }
onMounted(load)
</script>
